// src/pages/ProductsPage/index.jsx

import React, { useEffect, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useParams } from 'react-router-dom';
import { fetchProductsByCategory, fetchAllProducts } from '../../store/slices/productsSlice';
import ProductCard from '../../components/ProductCard';
import FilterBar from '../../components/FilterBar';
import s from './ProductsPage.module.css';

const ProductsPage = () => {
  const dispatch = useDispatch();
  // Получаем ID категории из URL (будет undefined, если маршрут /products)
  const { id } = useParams(); 

  // Получаем данные о продуктах и статусе загрузки
  const { 
      list: products, 
      status, 
      error,
      filters // Получаем текущие фильтры из Redux
  } = useSelector(state => state.products);

  // Получаем список категорий для определения названия текущей категории
  const categoriesList = useSelector(state => state.categories.list);

  // --- 1. ЗАГРУЗКА ДАННЫХ ---
  useEffect(() => {
    // В зависимости от наличия id, диспатчим нужный thunk
    if (id) {
      // Маршрут /categories/:id
      dispatch(fetchProductsByCategory(id));
    } else {
      // Маршрут /products
      dispatch(fetchAllProducts());
    }
    // Зависимость [dispatch, id] гарантирует, что при смене ID категории, данные обновятся
  }, [dispatch, id]);

  // --- 2. ОПРЕДЕЛЕНИЕ ЗАГОЛОВКА ---
  const pageTitle = useMemo(() => {
    // Если id есть, ищем категорию по ID
    if (id) {
        const currentCategory = categoriesList.find(cat => cat.id === +id);
        return currentCategory ? currentCategory.title : 'Товары категории';
    }
    // Если id нет
    return 'Все товары';
  }, [id, categoriesList]);

  // --- 3. РЕНДЕРИНГ СОСТОЯНИЙ (Loading/Error) ---
  if (status === 'loading') {
    return <div className={s.container}>Загрузка товаров...</div>;
  }

  if (status === 'failed') {
    return <div className={s.container}>Ошибка при загрузке: {error}</div>;
  }

  if (products.length === 0 && status === 'succeeded') {
      // Проверяем, если фильтры применены, выводим сообщение о фильтрации, иначе - о пустоте
      const isFiltered = filters.priceFrom || filters.priceTo || filters.discount !== false || filters.sortBy !== 'default';

      return (
          <div className={s.container}>
              <h1>{pageTitle}</h1>
              <FilterBar />
              <p className={s.emptyMessage}>
                  {isFiltered 
                   ? 'Нет товаров, соответствующих текущим фильтрам.' 
                   : 'Товары не найдены.'}
              </p>
          </div>
      );
  }

  // --- 4. ОСНОВНОЙ РЕНДЕРИНГ ---
  return (
    <div className={s.container}>
      <h1>{pageTitle}</h1>

      <FilterBar /> {/* Компонент для фильтрации и сортировки */}

      <div className={s.list}>
        {products.map(product => (
          <ProductCard 
            key={product.id}
            id={product.id}
            title={product.title}
            price={product.price}
            discont_price={product.discont_price}
            image={product.image}
          />
        ))}
      </div>
    </div>
  );
};

export default ProductsPage;
